CREATE OR REPLACE PROCEDURE tcel_registrar_operacao(nm_tabela varchar2) IS

nr_sequencia_w  number(10);
BEGIN  

if (nm_tabela = 'TCEL_REDE_IMP_PACOTE') then

  select  nvl(max(nr_operacao),0)+1
  into    nr_sequencia_w
  from    TCEL_REDE_IMP_PACOTE
  where   nr_operacao is null;


  update  TCEL_REDE_IMP_PACOTE
  set     nr_operacao = nr_sequencia_w
  where   nr_operacao is null;

end if;

commit;

END tcel_registrar_operacao;
/

