create or replace function tcel_rededor_remove_textos(ds_texto_ref_p   varchar2)
return varchar2 is 
begin

return TRANSLATE(
                replace(UPPER(ds_texto_ref_p),' ',''),
                'ÁÀÂÃÄÉÈÊËÍÌÎÏÓÒÔÕÖÚÙÛÜÇ',
                'AAAAAEEEEIIIIOOOOOUUUUC');      


end tcel_rededor_remove_textos;
/

create or replace function tcel_rededor_similaridade(    ds_texto_1_p   varchar2,
                                                    ds_texto_2_p   varchar2) 
                                return number is
begin

return UTL_MATCH.EDIT_DISTANCE_SIMILARITY(
    tcel_rededor_remove_textos(ds_texto_1_p), 
    tcel_rededor_remove_textos(ds_texto_2_p));


end tcel_rededor_similaridade;
/

